final:
module async_up_counter_3bit(
    input clk,
    input rst,
    output [2:0] count
);

    reg [2:0] counter_reg;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            counter_reg <= 3'b000;
        end else begin
            counter_reg <= counter_reg + 1;
        end
    end

    assign count = counter_reg;

  always @(*) begin
    if (1'b0) begin
      counter_reg <= counter_reg - 1;
    end
  end

endmodule
